    51→function ReleasesPageInner() {
    52→  const searchParams = useSearchParams();
    53→  const initialProject = searchParams.get("project") ?? "all";
    54→  const [page, setPage] = useState(1);
    55→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    56→
    57→  /* Fetch projects for the filter dropdown */
    58→  const { data: projectsData } = useSWR("projects-for-filter", async () => {
    59→    const firstPage = await projectsApi.list(1, 100);
    60→    return firstPage;
    61→  });
    62→
    63→  /* Fetch releases — scoped by project or all */
    64→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    65→    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    66→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE)
    67→  );
    68→
    69→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    70→    projectFilter === "all" ? ["all-releases", page] : null,
    71→    () => releasesApi.list(page, PER_PAGE)
    72→  );
    73→
    74→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    75→
    76→  /* Releases come pre-enriched with project/source metadata from the backend */
    77→  const releases: Release[] =
    78→    projectFilter !== "all"
    79→      ? scopedData?.data ?? []
    80→      : allReleasesData?.data ?? [];
    81→
    82→  /* Pagination math */
    83→  const activeData = projectFilter !== "all" ? scopedData : allReleasesData;
    84→  const total = activeData?.meta?.total ?? 0;
    85→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    86→  const startRow = (page - 1) * PER_PAGE + 1;
