   112→          style={{
   113→            fontFamily: "var(--font-dm-sans)",
   114→            fontSize: "13px",
   115→            color: "#111113",
   116→            border: "1px solid #e8e8e5",
   117→          }}
   118→          onFocus={(e) =>
   119→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   120→          }
   121→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   122→        >
   123→          <option value="all">All Projects</option>
   124→          {projectsData?.data.map((p: Project) => (
   125→            <option key={p.id} value={p.id}>
   126→              {p.name}
   127→            </option>
   128→          ))}
   129→        </select>
   130→      </div>
   131→
   132→      {/* Table card */}
   133→      <div
   134→        className="overflow-hidden rounded-lg bg-white"
   135→        style={{ border: "1px solid #e8e8e5" }}
   136→      >
   137→        {isLoading ? (
   138→          <div
   139→            className="py-16 text-center"
   140→            style={{
   141→              fontFamily: "var(--font-dm-sans)",
   142→              fontSize: "13px",
   143→              color: "#6b7280",
   144→            }}
   145→          >
   146→            Loading...
   147→          </div>
   148→        ) : releases.length === 0 ? (
   149→          <div className="py-16 text-center">
   150→            <p
   151→              style={{
   152→                fontFamily: "var(--font-fraunces)",
   153→                fontStyle: "italic",
   154→                fontSize: "15px",
   155→                color: "#9ca3af",
   156→              }}
   157→            >
   158→              No releases ingested yet
   159→            </p>
   160→          </div>
   161→        ) : (
   162→          <table className="w-full">
   163→            <thead>
   164→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   165→                {["Project", "Provider", "Repository", "Version", "Released", "Age", ""].map(
   166→                  (col) => (
   167→                    <th
   168→                      key={col}
   169→                      className="px-4 py-3 text-left"
   170→                      style={{
   171→                        fontFamily: "var(--font-dm-sans)",
   172→                        fontSize: "11px",
   173→                        fontWeight: 600,
   174→                        textTransform: "uppercase" as const,
   175→                        letterSpacing: "0.08em",
   176→                        color: "#9ca3af",
   177→                      }}
   178→                    >
   179→                      {col}
   180→                    </th>
   181→                  )
   182→                )}
   183→              </tr>
   184→            </thead>
   185→            <tbody>
   186→              {releases.map((release) => (
   187→                <tr
   188→                  key={release.id}
   189→                  className="transition-colors hover:bg-[#fafaf9]"
   190→                  style={{ borderBottom: "1px solid #e8e8e5" }}
   191→                >
   192→                  {/* Project */}
   193→                  <td className="px-4 py-3">
   194→                    {release.project_id ? (
   195→                      <Link
   196→                        href={`/projects/${release.project_id}`}
   197→                        className="hover:underline"
   198→                        style={{
   199→                          fontFamily: "var(--font-dm-sans)",
   200→                          fontSize: "13px",
   201→                          color: "#111113",
   202→                          fontWeight: 500,
   203→                        }}
   204→                      >
   205→                        {release.project_name ?? "\u2014"}
   206→                      </Link>
   207→                    ) : (
   208→                      <span
   209→                        style={{
   210→                          fontFamily: "var(--font-dm-sans)",
   211→                          fontSize: "13px",
   212→                          color: "#9ca3af",
   213→                        }}
   214→                      >
   215→                        {"\u2014"}
   216→                      </span>
   217→                    )}
   218→                  </td>
   219→
   220→                  {/* Provider */}
   221→                  <td className="px-4 py-3">
   222→                    {release.provider ? (
   223→                      <ProviderBadge provider={release.provider} />
   224→                    ) : (
   225→                      <span
   226→                        style={{
   227→                          fontFamily: "var(--font-dm-sans)",
   228→                          fontSize: "13px",
   229→                          color: "#9ca3af",
   230→                        }}
   231→                      >
   232→                        {"\u2014"}
   233→                      </span>
   234→                    )}
   235→                  </td>
   236→
   237→                  {/* Repository */}
   238→                  <td className="px-4 py-3">
   239→                    <span
   240→                      style={{
   241→                        fontFamily: "'JetBrains Mono', monospace",
   242→                        fontSize: "12px",
   243→                        color: "#374151",
   244→                      }}
   245→                    >
   246→                      {release.repository ?? release.source_id}
   247→                    </span>
   248→                  </td>
   249→
   250→                  {/* Version */}
   251→                  <td className="px-4 py-3">
   252→                    <Link href={`/releases/${release.id}`}>
   253→                      <VersionChip version={release.version} />
   254→                    </Link>
   255→                  </td>
   256→
   257→                  {/* Released date */}
   258→                  <td className="px-4 py-3">
   259→                    <span
   260→                      style={{
   261→                        fontFamily: "var(--font-dm-sans)",
   262→                        fontSize: "13px",
   263→                        color: "#6b7280",
   264→                      }}
   265→                    >
   266→                      {release.released_at
   267→                        ? new Date(release.released_at).toLocaleDateString()
   268→                        : "\u2014"}
   269→                    </span>
   270→                  </td>
   271→
   272→                  {/* Age */}
   273→                  <td className="px-4 py-3">
   274→                    <span
   275→                      style={{
   276→                        fontFamily: "var(--font-dm-sans)",
   277→                        fontSize: "13px",
   278→                        color: "#9ca3af",
   279→                      }}
   280→                    >
   281→                      {timeAgo(release.released_at ?? release.created_at)}
   282→                    </span>
   283→                  </td>
   284→
   285→                  {/* Provider link */}
   286→                  <td className="px-4 py-3">
   287→                    {release.provider && release.repository && (() => {
   288→                      const url = getProviderUrl(release.provider, release.repository, release.version);
   289→                      return url ? (
   290→                        <a
   291→                          href={url}
   292→                          target="_blank"
   293→                          rel="noopener noreferrer"
   294→                          className="inline-flex items-center transition-colors hover:opacity-70"
   295→                          style={{ color: "#9ca3af" }}
   296→                          title="View on provider"
   297→                        >
   298→                          <ExternalLink size={14} />
   299→                        </a>
   300→                      ) : null;
   301→                    })()}
   302→                  </td>
   303→                </tr>
   304→              ))}
   305→            </tbody>
   306→          </table>
   307→        )}
   308→      </div>
   309→
   310→      {/* Pagination */}
   311→      {total > 0 && (
   312→        <div className="flex items-center justify-between">
   313→          <span
   314→            style={{
   315→              fontFamily: "var(--font-dm-sans)",
   316→              fontSize: "13px",
   317→              color: "#9ca3af",
   318→            }}
   319→          >
   320→            {startRow}&ndash;{endRow} of {total}
   321→          </span>
   322→          <div className="flex items-center gap-2">
   323→            <button
   324→              disabled={page <= 1}
   325→              onClick={() => setPage(page - 1)}
   326→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   327→              style={{
   328→                fontFamily: "var(--font-dm-sans)",
   329→                fontSize: "13px",
   330→                color: "#374151",
   331→                border: "1px solid #e8e8e5",
   332→              }}
   333→            >
   334→              Previous
   335→            </button>
   336→            <button
   337→              disabled={page >= totalPages}
   338→              onClick={() => setPage(page + 1)}
   339→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   340→              style={{
   341→                fontFamily: "var(--font-dm-sans)",
   342→                fontSize: "13px",
   343→                color: "#374151",
   344→                border: "1px solid #e8e8e5",
   345→              }}
   346→            >
   347→              Next
   348→            </button>
   349→          </div>
   350→        </div>
   351→      )}
   352→    </div>
   353→  );
   354→}
   355→

