   171→          className="font-mono text-sm"
   172→        />
   173→        <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
   174→      </div>
   175→      {(provider === "github" || provider === "gitlab") && (
   176→        <div className="flex items-center gap-3">
   177→          <Switch checked={excludePrereleases} onCheckedChange={setExcludePrereleases} />
   178→          <Label>Exclude Pre-Releases</Label>
   179→        </div>
   180→      )}
   181→      <div className="flex items-center gap-3">
   182→        <Switch checked={enabled} onCheckedChange={setEnabled} />
   183→        <Label>Enabled</Label>
   184→      </div>
   185→      <div className="flex justify-end gap-2">
   186→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   187→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   188→      </div>
   189→    </form>
   190→  );
   191→
   192→  if (onSuccess) {
