  project_id: string;
  type: string;
  name: string;
  config: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface ContextSourceInput {
  type: string;
  name: string;
  config: Record<string, unknown>;
}

export interface SemanticRelease {
  id: string;
  project_id: string;
  project_name?: string;
  version: string;
  report?: SemanticReport;
  status: string;
  error?: string;
  created_at: string;
  completed_at?: string;
}

export interface SemanticReport {
  subject?: string;
  risk_level?: string;
  risk_reason?: string;
  status_checks?: string[];
  changelog_summary?: string;
  download_commands?: string[];
  download_links?: string[];
  summary?: string;
  availability?: string;
  adoption?: string;
  urgency?: string;
  recommendation?: string;
}

export interface AgentRun {
  id: string;
  project_id: string;
  semantic_release_id?: string;
  trigger: string;
  status: string;
  prompt_used?: string;
  error?: string;
  started_at?: string;
  completed_at?: string;
  created_at: string;
}

export interface NotificationChannel {
  id: string;
  name: string;
  type: string;
  config: Record<string, unknown>;
  created_at: string;
  updated_at: string;
}

export interface ChannelInput {
  type: string;
  name: string;
  config: Record<string, unknown>;
}

export interface Subscription {
  id: string;
  channel_id: string;
  type: "source_release" | "semantic_release";
  source_id?: string;
  project_id?: string;
  version_filter?: string;
  created_at: string;
}

export interface SubscriptionInput {
  channel_id: string;
  type: "source_release" | "semantic_release";
  source_id?: string;
  project_id?: string;
  version_filter?: string;
}

export interface BatchSubscriptionInput {
  channel_id: string;
  type: "source_release" | "semantic_release";
  project_ids?: string[];
  source_ids?: string[];
  version_filter?: string;
}

